 31→import kotlin.time.TimeSource.Monotonic
 32→
 33→internal class ContentCache {
 34→  private val contentMap: ConcurrentHashMap<String, CacheContent> = ConcurrentHashMap()
 35→  private val maxCacheSize = System.getenv("MAX_CACHE_SIZE")?.toInt() ?: 2048
 36→  private val maxLength = System.getenv("MAX_LENGTH")?.toInt() ?: (5 * 1048576)
 37→
 38→  class CacheContent(
 39→    internal val pageLines: List<String>,
 40→    internal val etag: String,
 41→    internal val contentLength: Int,
 42→    private val references: AtomicInt = AtomicInt(0),
 43→    private var referenced: TimeMark = Monotonic.markNow(),
 44→    private val created: TimeMark = Monotonic.markNow(),
 45→  ) {
 46→    val age: Duration get() = created.elapsedNow()
 47→    val lastReferenced: Duration get() = referenced.elapsedNow()
 48→    val hits get() = references.load()
 49→
 50→    fun markReferenced() {
 51→      referenced = Monotonic.markNow()
 52→      references += 1
 53→    }
 54→  }
 55→
 56→  val size get() = contentMap.size
 57→
 58→  fun sortedByLastReferenced(): List<Map.Entry<String, CacheContent>> =
 59→    contentMap.entries.sortedBy { it.value.lastReferenced }
 60→
 61→  fun remove(url: String) = contentMap.remove(url)
 62→
 63→  operator fun set(
 64→    url: String,
 65→    value: CacheContent,
 66→  ) {
 67→    contentMap[url] = value
 68→  }
 69→
 70→  operator fun get(url: String): CacheContent? = contentMap[url]
 71→
 72→  companion object {
 73→    private val logger = KotlinLogging.logger {}
 74→    internal val contentCache = ContentCache()
 75→
 76→    init {
 77→      logger.info { "Starting cache cleanup thread" }
 78→
 79→      thread(name = "Cache Cleanup") {
 80→        while (true) {
 81→          runCatching {
 82→            val overflow = contentCache.size - contentCache.maxCacheSize
 83→            if (overflow > 0) {
 84→              logger.info { "Cache size: ${contentCache.size} exceeds max: ${contentCache.maxCacheSize}" }
 85→              contentCache.contentMap.entries.sortedByDescending { it.value.lastReferenced }.take(overflow)
 86→                .forEach { (k, _) ->
 87→                  logger.info { "Removing $k from cache" }
 88→                  contentCache.remove(k)
 89→                }
 90→            }
 91→          }.onFailure { e ->
 92→            logger.error(e) { "Exception in Cache Cleanup ${e.simpleClassName} ${e.message}" }
 93→          }
 94→          Thread.sleep(5.minutes.inWholeMilliseconds)
 95→        }
 96→      }
 97→    }
 98→
 99→    private fun String.isInvalidContentType() =
100→      startsWith("application/") ||
101→        startsWith("image/") ||
102→        startsWith("video/") ||
103→        startsWith("model/") ||
104→        startsWith("font/") ||
105→        startsWith("audio/")
106→
107→    internal suspend fun fetchContent(url: String): List<String> {
108→      val cacheItem = contentCache[url]
109→      val response =
110→        HttpClient(CIO) {
111→          install(HttpRequestRetry) {
112→            retryOnServerErrors(maxRetries = 3)
113→            exponentialDelay()
114→          }
115→        }.let { client ->
116→          client.get(url) {
117→            if (cacheItem.isNotNull() && cacheItem.etag.isNotBlank()) {
118→              logger.info { "Setting ETag: ${cacheItem.etag} for url: ${url.removePrefix(RAW_PREFIX)}" }
119→              headers.append(HttpHeaders.IfNoneMatch, cacheItem.etag)
120→            }
121→          }
122→        }
123→
124→      response.headers[HttpHeaders.ContentType]?.also { contentType ->
125→        if (contentType.isInvalidContentType()) {
126→          val msg = "Invalid content type: $contentType"
127→          logger.warn { msg }
128→          throw IllegalArgumentException(msg)
129→        } else if (!contentType.startsWith("text/")) {
130→          logger.warn { "Unanticipated content type: $contentType" }
131→        }
132→      }
133→
134→      return when {
135→        response.status == HttpStatusCode.NotModified && cacheItem.isNotNull() -> {
136→          cacheItem.run {
137→            logger.info { "Returning cached content for ETag: $etag and url: ${url.removePrefix(RAW_PREFIX)}" }
138→            markReferenced()
139→            pageLines
140→          }
141→        }
142→
143→        else -> {
144→          val contentLength = HttpHeaders.ContentLength
145→          val length = response.headers[contentLength].toInt { "$contentLength header is null or not an integer" }
146→          if (length >= contentCache.maxLength) {
147→            val msg = "$contentLength exceeds maximum length: $length"
148→            logger.warn { msg }
149→            throw IllegalArgumentException(msg)
150→          }
151→
152→          val etag = response.headers[HttpHeaders.ETag] ?: ""
153→          val pageLines = response.body<String>().lines()
154→          if (etag.isNotBlank()) {
155→            logger.info { "Adding item to content cache -- ETag: $etag and url: ${url.removePrefix(RAW_PREFIX)}" }
156→            val now = Monotonic.markNow()
157→            contentCache[url] =
158→              CacheContent(
159→                pageLines = pageLines,
160→                etag = etag,
161→                contentLength = length,
162→                referenced = now,
163→                created = now,
164→              ).apply { markReferenced() }
165→          }
166→          pageLines
167→        }
168→      }
169→    }
170→  }
171→}
