package com.pambrose.srcref

import com.github.pambrose.common.util.isNotNull
import com.github.pambrose.common.util.simpleClassName
import com.pambrose.srcref.Urls.RAW_PREFIX
import com.pambrose.srcref.Urls.toInt
import io.github.oshai.kotlinlogging.KotlinLogging
import io.ktor.client.HttpClient
import io.ktor.client.call.body
import io.ktor.client.engine.cio.CIO
import io.ktor.client.plugins.HttpRequestRetry
import io.ktor.client.request.get
import io.ktor.http.HttpHeaders
import io.ktor.http.HttpStatusCode
import java.util.concurrent.ConcurrentHashMap
import kotlin.concurrent.atomics.AtomicInt
import kotlin.concurrent.atomics.plusAssign
import kotlin.concurrent.thread
import kotlin.time.Duration
import kotlin.time.Duration.Companion.minutes
import kotlin.time.TimeMark
import kotlin.time.TimeSource.Monotonic

internal class ContentCache {
  private val contentMap: ConcurrentHashMap<String, CacheContent> = ConcurrentHashMap()
  private val maxCacheSize = System.getenv("MAX_CACHE_SIZE")?.toInt() ?: 2048
  private val maxLength = System.getenv("MAX_LENGTH")?.toInt() ?: (5 * 1048576)

  class CacheContent(
    internal val pageLines: List<String>,
    internal val etag: String,
    internal val contentLength: Int,
    private val references: AtomicInt = AtomicInt(0),
    @Volatile private var referenced: TimeMark = Monotonic.markNow(),
    private val created: TimeMark = Monotonic.markNow(),
  ) {
    val age: Duration get() = created.elapsedNow()
    val lastReferenced: Duration get() = referenced.elapsedNow()
    val hits get() = references.load()

    fun markReferenced() {
      referenced = Monotonic.markNow()
      references += 1
    }
  }

  val size get() = contentMap.size

  fun sortedByLastReferenced(): List<Map.Entry<String, CacheContent>> =
    contentMap.entries.sortedBy { it.value.lastReferenced }

  fun remove(url: String) = contentMap.remove(url)

  operator fun set(
    url: String,
    value: CacheContent,
  ) {
    contentMap[url] = value
  }

  operator fun get(url: String): CacheContent? = contentMap[url]

  companion object {
    private val logger = KotlinLogging.logger {}
    internal val contentCache = ContentCache()

    private val httpClient =
      HttpClient(CIO) {
        install(HttpRequestRetry) {
          retryOnServerErrors(maxRetries = 3)
          exponentialDelay()
        }
      }

    init {
      logger.info { "Starting cache cleanup thread" }

      thread(name = "Cache Cleanup") {
        while (true) {
          runCatching {
            val overflow = contentCache.size - contentCache.maxCacheSize
            if (overflow > 0) {
              logger.info { "Cache size: ${contentCache.size} exceeds max: ${contentCache.maxCacheSize}" }
              contentCache.contentMap.entries.sortedByDescending { it.value.lastReferenced }.take(overflow)
                .forEach { (k, _) ->
                  logger.info { "Removing $k from cache" }
                  contentCache.remove(k)
                }
            }
          }.onFailure { e ->
            logger.error(e) { "Exception in Cache Cleanup ${e.simpleClassName} ${e.message}" }
          }
          Thread.sleep(5.minutes.inWholeMilliseconds)
        }
      }
    }

    private fun String.isInvalidContentType() =
      startsWith("application/") ||
        startsWith("image/") ||
        startsWith("video/") ||
        startsWith("model/") ||
        startsWith("font/") ||
        startsWith("audio/")

    internal suspend fun fetchContent(url: String): List<String> {
      val cacheItem = contentCache[url]
      val response =
        httpClient.get(url) {
          if (cacheItem.isNotNull() && cacheItem.etag.isNotBlank()) {
            logger.info { "Setting ETag: ${cacheItem.etag} for url: ${url.removePrefix(RAW_PREFIX)}" }
            headers.append(HttpHeaders.IfNoneMatch, cacheItem.etag)
          }
        }

      response.headers[HttpHeaders.ContentType]?.also { contentType ->
        if (contentType.isInvalidContentType()) {
          val msg = "Invalid content type: $contentType"
          logger.warn { msg }
          throw IllegalArgumentException(msg)
        } else if (!contentType.startsWith("text/")) {
          logger.warn { "Unanticipated content type: $contentType" }
        }
      }

      return when {
        response.status == HttpStatusCode.NotModified && cacheItem.isNotNull() -> {
          cacheItem.run {
            logger.info { "Returning cached content for ETag: $etag and url: ${url.removePrefix(RAW_PREFIX)}" }
            markReferenced()
            pageLines
          }
        }

        else -> {
          val contentLength = HttpHeaders.ContentLength
          val length = response.headers[contentLength].toInt { "$contentLength header is null or not an integer" }
          if (length >= contentCache.maxLength) {
            val msg = "$contentLength exceeds maximum length: $length"
            logger.warn { msg }
            throw IllegalArgumentException(msg)
          }

          val etag = response.headers[HttpHeaders.ETag] ?: ""
          val pageLines = response.body<String>().lines()
          if (etag.isNotBlank()) {
            logger.info { "Adding item to content cache -- ETag: $etag and url: ${url.removePrefix(RAW_PREFIX)}" }
            val now = Monotonic.markNow()
            contentCache[url] =
              CacheContent(
                pageLines = pageLines,
                etag = etag,
                contentLength = length,
                referenced = now,
                created = now,
              ).apply { markReferenced() }
          }
          pageLines
        }
      }
    }
  }
}

package com.pambrose.srcref

import com.github.pambrose.common.util.encode
import com.github.pambrose.common.util.isNotNull
import com.pambrose.srcref.ContentCache.Companion.fetchContent
import com.pambrose.srcref.Endpoints.GITHUB
import com.pambrose.srcref.Endpoints.PROBLEM
import com.pambrose.srcref.Main.logger
import com.pambrose.srcref.QueryParams.ACCOUNT
import com.pambrose.srcref.QueryParams.BEGIN_OCCURRENCE
import com.pambrose.srcref.QueryParams.BEGIN_OFFSET
import com.pambrose.srcref.QueryParams.BEGIN_REGEX
import com.pambrose.srcref.QueryParams.BEGIN_TOPDOWN
import com.pambrose.srcref.QueryParams.BRANCH
import com.pambrose.srcref.QueryParams.END_OCCURRENCE
import com.pambrose.srcref.QueryParams.END_OFFSET
import com.pambrose.srcref.QueryParams.END_REGEX
import com.pambrose.srcref.QueryParams.END_TOPDOWN
import com.pambrose.srcref.QueryParams.PATH
import com.pambrose.srcref.QueryParams.REPO
import com.pambrose.srcref.pages.Common.hasValues
import java.util.regex.PatternSyntaxException
import kotlin.time.measureTimedValue
import org.apache.commons.text.StringEscapeUtils.escapeHtml4

object Urls {
  internal const val MSG = "msg"
  internal const val RAW_PREFIX = "https://raw.githubusercontent.com"

  internal fun Map<String, String?>.toQueryParams(ignoreEndParams: Boolean) =
    filter { if (ignoreEndParams) it.key !in QueryParams.optionalParams else true }
      .map { (k, v) -> if (v.isNotNull()) "$k=${v.encode()}" else "" }
      .filter { it.isNotBlank() }
      .joinToString("&")

  private fun Map<String, String?>.missingEndRegex() = this[END_REGEX.arg]?.isBlank() ?: true

  internal fun srcrefToGithubUrl(
    params: Map<String, String?>,
    escapeHtml4: Boolean = false,
    prefix: String,
  ) = "$prefix/$GITHUB?${params.toQueryParams(params.missingEndRegex())}"
    .let { if (escapeHtml4) escapeHtml4(it) else it }

  internal inline fun String?.toInt(block: () -> String) =
    try {
      this?.toInt() ?: throw IllegalArgumentException(block())
    } catch (e: NumberFormatException) {
      throw IllegalArgumentException(block())
    }

  // This returns an url and an error message
  internal suspend fun githubRangeUrl(
    params: Map<String, String?>,
    prefix: String,
  ): Pair<String, String> =
    runCatching {
      if (!params.hasValues()) {
        "" to ""
      } else {
        val account = ACCOUNT.required(params)
        val repo = REPO.required(params)
        val path = PATH.required(params).let { if (it.startsWith("/")) it.substring(1) else it }
        val branch = BRANCH.required(params)

        val url = githubRawUrl(account, repo, path, branch)
        val (lines, duration) = measureTimedValue { fetchContent(url) }
        logger.info { "Read ${url.removePrefix(RAW_PREFIX)} in $duration" }

        val beginOccurrenceStr = BEGIN_OCCURRENCE.defaultIfNull(params)
        val beginOccurrence = beginOccurrenceStr.toInt { "Invalid Begin Occurrence value: $beginOccurrenceStr" }
        val beginOffsetStr = BEGIN_OFFSET.defaultIfNull(params)
        val beginOffset = beginOffsetStr.toInt { "Invalid Begin Offset value: $beginOffsetStr" }
        val beginLinenum =
          calcLineNumber(
            lines = lines,
            pattern = BEGIN_REGEX.required(params),
            occurrence = beginOccurrence,
            offset = beginOffset,
            topDown = BEGIN_TOPDOWN.defaultIfNull(params).toBoolean(),
            desc = "begin",
          ).also { if (it < 1) throw IllegalArgumentException("Begin line number is less than 1") }

        val endLinenum =
          if (END_REGEX.defaultIfNull(params).isBlank()) {
            -1
          } else {
            val endOccurrenceStr = END_OCCURRENCE.defaultIfNull(params)
            val endOccurrence = endOccurrenceStr.toInt { "Invalid End Occurrence value: $endOccurrenceStr" }
            val endOffsetStr = END_OFFSET.defaultIfNull(params)
            val endOffset = endOffsetStr.toInt { "Invalid End Offset value: $endOffsetStr" }
            calcLineNumber(
              lines = lines,
              pattern = END_REGEX.defaultIfNull(params),
              occurrence = endOccurrence,
              offset = endOffset,
              topDown = END_TOPDOWN.defaultIfNull(params).toBoolean(),
              desc = "end",
            ).also { if (it < 1) throw IllegalArgumentException("End line number is less than 1") }
          }
        githubSourceUrl(account, repo, branch, path, beginLinenum, endLinenum) to ""
      }
    }.getOrElse { e ->
      val msg = "${e::class.simpleName}: ${e.message}"
      logger.info { "Input problem: $msg $params" }
      "$prefix/$PROBLEM?$MSG=${msg.encode()}&${params.toQueryParams(false)}" to msg
    }

  private fun githubSourceUrl(
    username: String,
    repoName: String,
    branchName: String,
    path: String = "",
    beginLineNum: Int,
    endLineNum: Int,
  ): String {
    val suffix = if (endLineNum > 0 && beginLineNum != endLineNum) "-L$endLineNum" else ""
    return "https://github.com/$username/$repoName/blob/$branchName/$path#L$beginLineNum$suffix"
  }

  private fun githubRawUrl(
    username: String,
    repoName: String,
    path: String = "",
    branchName: String,
  ) = "$RAW_PREFIX/$username/$repoName/$branchName/$path"

  internal fun calcLineNumber(
    lines: List<String>,
    pattern: String,
    occurrence: Int,
    offset: Int,
    topDown: Boolean,
    desc: String = "",
  ): Int =
    runCatching {
      require(occurrence >= 1) { "Occurrence must be >= 1, got: $occurrence" }
      val regex = Regex(pattern)
      (
        (if (topDown) lines else lines.asReversed())
          .asSequence()
          .mapIndexed { index, s -> (if (topDown) index else (lines.size - index - 1)) to s.contains(regex) }
          .filter { it.second }
          .drop(occurrence - 1)
          .first().first
        ) + offset + 1
    }.getOrElse { e ->
      throw when (e) {
        is PatternSyntaxException -> {
          IllegalArgumentException("Invalid regex:\"${pattern}\" - ${e.message}")
        }

        is NoSuchElementException -> {
          IllegalArgumentException("Required matches ($occurrence) not found for $desc regex: \"$pattern\"")
        }

        else -> {
          logger.error { "Error in calcLineNumber(): ${e::class.simpleName}: ${e.message}" }
          e
        }
      }
    }
}

package com.pambrose.srcref

internal enum class QueryParams(
  internal val arg: String,
  private val defaultValue: String,
  private val optional: Boolean,
) {
  ACCOUNT("account", "", false),
  REPO("repo", "", false),
  BRANCH("branch", System.getenv("DEFAULT_BRANCH") ?: "master", false),
  PATH("path", "", false),
  BEGIN_REGEX("bregex", "", false),
  BEGIN_OCCURRENCE("boccur", "1", false),
  BEGIN_OFFSET("boffset", "0", false),
  BEGIN_TOPDOWN("btopd", "true", false),
  END_REGEX("eregex", "", true),
  END_OCCURRENCE("eoccur", "1", true),
  END_OFFSET("eoffset", "0", true),
  END_TOPDOWN("etopd", "true", true),
  ;

  fun defaultIfNull(params: Map<String, String?>) = params[arg] ?: defaultValue

  fun defaultIfBlank(params: Map<String, String?>) = (params[arg] ?: "").let { it.ifBlank { defaultValue } }

  fun required(params: Map<String, String?>) =
    (params[arg] ?: "").let { it.ifBlank { throw IllegalArgumentException("Missing: $arg value") } }

  companion object {
    val optionalParams = entries.filter { it.optional }.map { it.arg }
  }
}

