import com.pambrose.srcref.QueryParams
import com.pambrose.srcref.QueryParams.ACCOUNT
import com.pambrose.srcref.QueryParams.BEGIN_OCCURRENCE
import com.pambrose.srcref.QueryParams.BEGIN_OFFSET
import com.pambrose.srcref.QueryParams.BEGIN_TOPDOWN
import com.pambrose.srcref.QueryParams.BRANCH
import com.pambrose.srcref.QueryParams.END_OCCURRENCE
import com.pambrose.srcref.QueryParams.END_OFFSET
import com.pambrose.srcref.QueryParams.END_REGEX
import com.pambrose.srcref.QueryParams.END_TOPDOWN
import com.pambrose.srcref.QueryParams.PATH
import com.pambrose.srcref.QueryParams.REPO
import io.kotest.assertions.throwables.shouldThrow
import io.kotest.core.spec.style.StringSpec
import io.kotest.matchers.shouldBe
import io.kotest.matchers.string.shouldContain

class QueryParamsTests :
  StringSpec(
    {
      // arg property

      "ACCOUNT arg is account" { ACCOUNT.arg shouldBe "account" }
      "REPO arg is repo" { REPO.arg shouldBe "repo" }
      "BRANCH arg is branch" { BRANCH.arg shouldBe "branch" }
      "PATH arg is path" { PATH.arg shouldBe "path" }

      // defaultIfNull

      "defaultIfNull returns value when present" {
        ACCOUNT.defaultIfNull(mapOf("account" to "testuser")) shouldBe "testuser"
      }

      "defaultIfNull returns default when key missing" {
        BEGIN_OCCURRENCE.defaultIfNull(emptyMap()) shouldBe "1"
      }

      "defaultIfNull returns default when value is null" {
        BEGIN_OCCURRENCE.defaultIfNull(mapOf("boccur" to null)) shouldBe "1"
      }

      "defaultIfNull returns empty string when value is empty" {
        ACCOUNT.defaultIfNull(mapOf("account" to "")) shouldBe ""
      }

      "defaultIfNull uses correct defaults" {
        BEGIN_OFFSET.defaultIfNull(emptyMap()) shouldBe "0"
        BEGIN_TOPDOWN.defaultIfNull(emptyMap()) shouldBe "true"
        END_OCCURRENCE.defaultIfNull(emptyMap()) shouldBe "1"
        END_OFFSET.defaultIfNull(emptyMap()) shouldBe "0"
        END_TOPDOWN.defaultIfNull(emptyMap()) shouldBe "true"
        END_REGEX.defaultIfNull(emptyMap()) shouldBe ""
      }

      // defaultIfBlank

      "defaultIfBlank returns value when non-blank" {
        BEGIN_OCCURRENCE.defaultIfBlank(mapOf("boccur" to "3")) shouldBe "3"
      }

      "defaultIfBlank returns default when value is blank" {
        BEGIN_OCCURRENCE.defaultIfBlank(mapOf("boccur" to "")) shouldBe "1"
      }

      "defaultIfBlank returns default when value is whitespace" {
        BEGIN_OCCURRENCE.defaultIfBlank(mapOf("boccur" to "   ")) shouldBe "1"
      }

      "defaultIfBlank returns default when key missing" {
        BEGIN_OCCURRENCE.defaultIfBlank(emptyMap()) shouldBe "1"
      }

      "defaultIfBlank returns default when value is null" {
        BEGIN_OCCURRENCE.defaultIfBlank(mapOf("boccur" to null)) shouldBe "1"
      }

      // required

      "required returns value when present and non-blank" {
        ACCOUNT.required(mapOf("account" to "user")) shouldBe "user"
      }

      "required throws when value is blank" {
        val exception =
          shouldThrow<IllegalArgumentException> {
            ACCOUNT.required(mapOf("account" to ""))
          }
        exception.message shouldContain "Missing: account"
      }

      "required throws when key is missing" {
        val exception =
          shouldThrow<IllegalArgumentException> {
            ACCOUNT.required(emptyMap())
          }
        exception.message shouldContain "Missing: account"
      }

      "required throws when value is null" {
        val exception =
          shouldThrow<IllegalArgumentException> {
            REPO.required(mapOf("repo" to null))
          }
        exception.message shouldContain "Missing: repo"
      }

      // optionalParams

      "optionalParams contains exactly the end params" {
        QueryParams.optionalParams shouldBe listOf("eregex", "eoccur", "eoffset", "etopd")
      }

      "all non-optional params are not in optionalParams" {
        val required = listOf("account", "repo", "branch", "path", "bregex", "boccur", "boffset", "btopd")
        required.forEach { arg ->
          (arg !in QueryParams.optionalParams) shouldBe true
        }
      }
    },
  )

