import io.kotest.matchers.shouldBe
import io.kotest.matchers.shouldNotBe

class ContentCacheTests :
  StringSpec(
    {
      // Basic cache operations

      "cache set and get" {
        val cache = ContentCache()
        val content =
          CacheContent(
            pageLines = listOf("line1", "line2"),
            etag = "\"abc123\"",
            contentLength = 100,
          )
        cache["http://test"] = content
        cache["http://test"] shouldBe content
      }

      "cache get returns null for missing key" {
        val cache = ContentCache()
        cache["http://missing"] shouldBe null
      }

      "cache remove deletes entry" {
        val cache = ContentCache()
        val content = CacheContent(listOf("line1"), "\"abc\"", 50)
        cache["http://test"] = content
        cache.remove("http://test")
        cache["http://test"] shouldBe null
      }

      "cache remove returns null for missing key" {
        val cache = ContentCache()
        cache.remove("http://missing") shouldBe null
      }

      "cache size reflects entries" {
        val cache = ContentCache()
        cache.size shouldBe 0
        cache["http://a"] = CacheContent(listOf(), "\"a\"", 0)
        cache.size shouldBe 1
        cache["http://b"] = CacheContent(listOf(), "\"b\"", 0)
        cache.size shouldBe 2
        cache.remove("http://a")
        cache.size shouldBe 1
      }

      "cache set overwrites existing entry" {
        val cache = ContentCache()
        val content1 = CacheContent(listOf("v1"), "\"tag1\"", 10)
        val content2 = CacheContent(listOf("v2"), "\"tag2\"", 20)
        cache["http://test"] = content1
        cache["http://test"] = content2
        cache["http://test"]!!.etag shouldBe "\"tag2\""
        cache.size shouldBe 1
      }

      // CacheContent properties

      "CacheContent initial hits is 0" {
        val content = CacheContent(listOf(), "\"tag\"", 0)
        content.hits shouldBe 0
      }

      "CacheContent markReferenced increments hits" {
        val content = CacheContent(listOf(), "\"tag\"", 0)
        content.markReferenced()
        content.hits shouldBe 1
        content.markReferenced()
        content.hits shouldBe 2
        content.markReferenced()
        content.hits shouldBe 3
      }

      "CacheContent age is non-negative" {
        val content = CacheContent(listOf(), "\"tag\"", 0)
        (content.age.isNegative()) shouldBe false
      }

      "CacheContent lastReferenced is non-negative" {
        val content = CacheContent(listOf(), "\"tag\"", 0)
        (content.lastReferenced.isNegative()) shouldBe false
      }

      "CacheContent age increases over time" {
        val content = CacheContent(listOf(), "\"tag\"", 0)
        val age1 = content.age
        Thread.sleep(15)
        val age2 = content.age
        (age2 > age1) shouldBe true
      }

      "CacheContent lastReferenced resets on markReferenced" {
        val content = CacheContent(listOf(), "\"tag\"", 0)
        Thread.sleep(20)
        val before = content.lastReferenced
        content.markReferenced()
        val after = content.lastReferenced
        (after < before) shouldBe true
      }

      "CacheContent stores pageLines correctly" {
        val lines = listOf("line1", "line2", "line3")
        val content = CacheContent(lines, "\"tag\"", 100)
        content.pageLines shouldBe lines
        content.pageLines.size shouldBe 3
      }

      "CacheContent stores etag and contentLength" {
        val content = CacheContent(listOf(), "\"W/abc123\"", 42)
        content.etag shouldBe "\"W/abc123\""
        content.contentLength shouldBe 42
      }

      // sortedByLastReferenced

      "sortedByLastReferenced returns entries ordered by recency" {
        val cache = ContentCache()
        val old = CacheContent(listOf(), "\"old\"", 0)
        cache["http://old"] = old
        Thread.sleep(15)
        val newer = CacheContent(listOf(), "\"new\"", 0)
        cache["http://new"] = newer

        val sorted = cache.sortedByLastReferenced()
        sorted.size shouldBe 2
        // sortedBy lastReferenced ascending: smallest elapsed time (most recent) first
        sorted.first().key shouldBe "http://new"
        sorted.last().key shouldBe "http://old"
      }

      "sortedByLastReferenced respects markReferenced" {
        val cache = ContentCache()
        val first = CacheContent(listOf(), "\"first\"", 0)
        cache["http://first"] = first
        Thread.sleep(15)
        val second = CacheContent(listOf(), "\"second\"", 0)
        cache["http://second"] = second
        Thread.sleep(15)

        // Mark first as recently referenced, making it more recent than second
        first.markReferenced()

        val sorted = cache.sortedByLastReferenced()
        sorted.first().key shouldBe "http://first"
        sorted.last().key shouldBe "http://second"
      }

      "sortedByLastReferenced with empty cache" {
        val cache = ContentCache()
        cache.sortedByLastReferenced() shouldBe emptyList()
      }

      "multiple caches are independent" {
        val cache1 = ContentCache()
        val cache2 = ContentCache()
        cache1["http://test"] = CacheContent(listOf("a"), "\"1\"", 1)
        cache2["http://test"] shouldBe null
        cache1.size shouldBe 1
        cache2.size shouldBe 0
      }
    },
  )

