import com.pambrose.srcref.Api
import com.pambrose.srcref.Endpoints
import com.pambrose.srcref.pages.Common
import com.pambrose.srcref.startsWithList
import io.kotest.core.spec.style.StringSpec
import io.kotest.matchers.shouldBe
import io.kotest.matchers.string.shouldContain
import io.kotest.matchers.string.shouldNotContain
import io.kotest.matchers.string.shouldStartWith

class UtilTests :
  StringSpec(
    {
      // startsWithList

      "startsWithList returns true when matching first prefix" {
        "/ping".startsWithList(listOf("/ping", "/health")) shouldBe true
      }

      "startsWithList returns true when matching later prefix" {
        "/health/check".startsWithList(listOf("/ping", "/health")) shouldBe true
      }

      "startsWithList returns false when no match" {
        "/other".startsWithList(listOf("/ping", "/health")) shouldBe false
      }

      "startsWithList returns false for empty prefix list" {
        "/ping".startsWithList(emptyList()) shouldBe false
      }

      "startsWithList matches partial prefix" {
        "/pingtest".startsWithList(listOf("/ping")) shouldBe true
      }

      "startsWithList is case-sensitive" {
        "/Ping".startsWithList(listOf("/ping")) shouldBe false
      }

      // Common.hasValues

      "hasValues returns true with non-blank value" {
        with(Common) {
          mapOf("a" to "value").hasValues() shouldBe true
        }
      }

      "hasValues returns true with mixed null and non-blank" {
        with(Common) {
          mapOf("a" to null, "b" to "value").hasValues() shouldBe true
        }
      }

      "hasValues returns false when all values null" {
        with(Common) {
          mapOf("a" to null, "b" to null).hasValues() shouldBe false
        }
      }

      "hasValues returns false when all values blank" {
        with(Common) {
          mapOf("a" to "", "b" to "   ").hasValues() shouldBe false
        }
      }

      "hasValues returns false for empty map" {
        with(Common) {
          emptyMap<String, String?>().hasValues() shouldBe false
        }
      }

      "hasValues returns false with mixed null and blank" {
        with(Common) {
          mapOf("a" to null, "b" to "", "c" to "  ").hasValues() shouldBe false
        }
      }

      // Endpoints

      "Endpoints paths are lowercase names" {
        Endpoints.EDIT.path shouldBe "edit"
        Endpoints.GITHUB.path shouldBe "github"
        Endpoints.PROBLEM.path shouldBe "problem"
        Endpoints.WHAT.path shouldBe "what"
        Endpoints.CACHE.path shouldBe "cache"
        Endpoints.VERSION.path shouldBe "version"
        Endpoints.PING.path shouldBe "ping"
        Endpoints.THREADDUMP.path shouldBe "threaddump"
      }

      "Endpoints toString returns path" {
        Endpoints.EDIT.toString() shouldBe "edit"
        Endpoints.PING.toString() shouldBe "ping"
        Endpoints.THREADDUMP.toString() shouldBe "threaddump"
      }

      "Endpoints entries has correct count" {
        Endpoints.entries.size shouldBe 8
      }

      // Api.srcrefUrl

      "srcrefUrl generates URL with default prefix" {
        val url =
          Api.srcrefUrl(
            account = "testuser",
            repo = "testrepo",
            path = "src/Main.kt",
            beginRegex = "fun main",
          )
        url shouldStartWith "https://www.srcref.com/github?"
        url shouldContain "account=testuser"
        url shouldContain "repo=testrepo"
      }

      "srcrefUrl with custom prefix" {
        val url =
          Api.srcrefUrl(
            account = "user",
            repo = "repo",
            path = "file.kt",
            beginRegex = "test",
            prefix = "https://custom.com",
          )
        url shouldStartWith "https://custom.com/github?"
      }

      "srcrefUrl with all parameters" {
        val url =
          Api.srcrefUrl(
            account = "user",
            repo = "repo",
            path = "file.kt",
            beginRegex = "begin",
            beginOccurrence = 2,
            beginOffset = 1,
            beginTopDown = false,
            endRegex = "end",
            endOccurrence = 3,
            endOffset = -1,
            endTopDown = false,
            prefix = "https://test.com",
            branch = "develop",
          )
        url shouldContain "boccur=2"
        url shouldContain "boffset=1"
        url shouldContain "btopd=false"
        url shouldContain "eregex=end"
        url shouldContain "eoccur=3"
        url shouldContain "eoffset=-1"
        url shouldContain "etopd=false"
        url shouldContain "branch=develop"
      }

      "srcrefUrl with HTML escaping" {
        val url =
          Api.srcrefUrl(
            account = "user",
            repo = "repo",
            path = "file.kt",
            beginRegex = "test",
            escapeHtml4 = true,
          )
        url shouldContain "&amp;"
      }

      "srcrefUrl without end regex omits optional params" {
        val url =
          Api.srcrefUrl(
            account = "user",
            repo = "repo",
            path = "file.kt",
            beginRegex = "test",
          )
        url shouldNotContain "eoccur"
        url shouldNotContain "eoffset"
        url shouldNotContain "etopd"
      }

      "srcrefUrl with end regex includes all end params" {
        val url =
          Api.srcrefUrl(
            account = "user",
            repo = "repo",
            path = "file.kt",
            beginRegex = "begin",
            endRegex = "end",
          )
        url shouldContain "eregex=end"
        url shouldContain "eoccur=1"
        url shouldContain "eoffset=0"
        url shouldContain "etopd=true"
      }

      "srcrefUrl with empty prefix" {
        val url =
          Api.srcrefUrl(
            account = "user",
            repo = "repo",
            path = "file.kt",
            beginRegex = "test",
            prefix = "",
          )
        url shouldStartWith "/github?"
      }

      "srcrefUrl default branch is master" {
        val url =
          Api.srcrefUrl(
            account = "user",
            repo = "repo",
            path = "file.kt",
            beginRegex = "test",
          )
        url shouldContain "branch=master"
      }
    },
  )

