import com.pambrose.srcref.Urls
import com.pambrose.srcref.Urls.calcLineNumber
import io.kotest.assertions.throwables.shouldThrow
import io.kotest.core.spec.style.StringSpec
import io.kotest.matchers.shouldBe
import io.kotest.matchers.string.shouldContain
import io.kotest.matchers.string.shouldNotContain
import io.kotest.matchers.string.shouldStartWith

class UrlsTests :
  StringSpec(
    {
      // toQueryParams

      "toQueryParams includes all non-null non-blank values" {
        with(Urls) {
          val params = mapOf("a" to "1", "b" to "2")
          val result = params.toQueryParams(false)
          result shouldContain "a=1"
          result shouldContain "b=2"
          result shouldContain "&"
        }
      }

      "toQueryParams filters out null values" {
        with(Urls) {
          val params = mapOf("a" to "1", "b" to null)
          val result = params.toQueryParams(false)
          result shouldBe "a=1"
        }
      }

      "toQueryParams filters out blank values" {
        with(Urls) {
          val params = mapOf("a" to "1", "b" to "")
          val result = params.toQueryParams(false)
          result shouldBe "a=1"
        }
      }

      "toQueryParams returns empty string for all-null map" {
        with(Urls) {
          val params = mapOf("a" to null, "b" to null)
          val result = params.toQueryParams(false)
          result shouldBe ""
        }
      }

      "toQueryParams returns empty string for empty map" {
        with(Urls) {
          val result = emptyMap<String, String?>().toQueryParams(false)
          result shouldBe ""
        }
      }

      "toQueryParams ignores optional end params when flag is true" {
        with(Urls) {
          val params =
            mapOf(
              "account" to "user",
              "eregex" to "pattern",
              "eoccur" to "1",
              "eoffset" to "0",
              "etopd" to "true",
            )
          val result = params.toQueryParams(true)
          result shouldBe "account=user"
        }
      }

      "toQueryParams includes end params when flag is false" {
        with(Urls) {
          val params = mapOf("account" to "user", "eregex" to "pattern")
          val result = params.toQueryParams(false)
          result shouldContain "account=user"
          result shouldContain "eregex=pattern"
        }
      }

      "toQueryParams URL-encodes values" {
        with(Urls) {
          val params = mapOf("path" to "src/Main.kt")
          val result = params.toQueryParams(false)
          result shouldContain "path=src%2FMain.kt"
        }
      }

      // srcrefToGithubUrl

      "srcrefToGithubUrl generates correct URL structure" {
        val params = mapOf("account" to "testuser", "repo" to "testrepo")
        val result = Urls.srcrefToGithubUrl(params, prefix = "https://example.com")
        result shouldStartWith "https://example.com/github?"
        result shouldContain "account=testuser"
        result shouldContain "repo=testrepo"
      }

      "srcrefToGithubUrl with HTML escaping escapes ampersands" {
        val params = mapOf("account" to "user", "repo" to "repo")
        val result = Urls.srcrefToGithubUrl(params, escapeHtml4 = true, prefix = "https://example.com")
        result shouldContain "&amp;"
        result shouldNotContain "&&"
      }

      "srcrefToGithubUrl without HTML escaping preserves ampersands" {
        val params = mapOf("account" to "user", "repo" to "repo")
        val result = Urls.srcrefToGithubUrl(params, escapeHtml4 = false, prefix = "https://example.com")
        result shouldContain "&"
        result shouldNotContain "&amp;"
      }

      "srcrefToGithubUrl omits end params when end regex missing" {
        val params =
          mapOf(
            "account" to "user",
            "bregex" to "test",
            "eregex" to null,
            "eoccur" to "2",
          )
        val result = Urls.srcrefToGithubUrl(params, prefix = "https://test.com")
        result shouldNotContain "eoccur"
      }

      "srcrefToGithubUrl includes end params when end regex present" {
        val params =
          mapOf(
            "account" to "user",
            "eregex" to "pattern",
            "eoccur" to "2",
          )
        val result = Urls.srcrefToGithubUrl(params, prefix = "https://test.com")
        result shouldContain "eregex="
        result shouldContain "eoccur=2"
      }

      "srcrefToGithubUrl omits end params when end regex blank" {
        val params =
          mapOf(
            "account" to "user",
            "eregex" to "",
            "eoccur" to "2",
          )
        val result = Urls.srcrefToGithubUrl(params, prefix = "https://test.com")
        result shouldNotContain "eoccur"
      }

      // githubRangeUrl (pre-network paths only)

      "githubRangeUrl with empty params returns empty pair" {
        val result = Urls.githubRangeUrl(emptyMap(), "http://test")
        result shouldBe ("" to "")
      }

      "githubRangeUrl with all-null params returns empty pair" {
        val params = mapOf("account" to null, "repo" to null)
        val result = Urls.githubRangeUrl(params, "http://test")
        result shouldBe ("" to "")
      }

      "githubRangeUrl with all-blank params returns empty pair" {
        val params = mapOf("account" to "", "repo" to "")
        val result = Urls.githubRangeUrl(params, "http://test")
        result shouldBe ("" to "")
      }

      "githubRangeUrl with missing account returns error" {
        val params = mapOf("bregex" to "test")
        val result = Urls.githubRangeUrl(params, "http://test")
        result.second shouldContain "Missing: account value"
        result.first shouldContain "problem"
      }

      "githubRangeUrl with missing repo returns error" {
        val params = mapOf("account" to "user", "bregex" to "test")
        val result = Urls.githubRangeUrl(params, "http://test")
        result.second shouldContain "Missing: repo value"
      }

      "githubRangeUrl with missing path returns error" {
        val params = mapOf("account" to "user", "repo" to "myrepo", "bregex" to "test", "branch" to "main")
        val result = Urls.githubRangeUrl(params, "http://test")
        result.second shouldContain "Missing: path value"
      }

      "githubRangeUrl with missing bregex returns error" {
        val params =
          mapOf(
            "account" to "user",
            "repo" to "myrepo",
            "path" to "file.kt",
            "branch" to "main",
          )
        val result = Urls.githubRangeUrl(params, "http://test")
        result.second shouldContain "Missing: bregex value"
      }

      // calcLineNumber error paths

      "calcLineNumber with invalid regex" {
        val exception =
          shouldThrow<IllegalArgumentException> {
            calcLineNumber(listOf("test"), "[invalid", 1, 0, true)
          }
        exception.message shouldContain "Invalid regex"
      }

      "calcLineNumber when pattern not found" {
        val exception =
          shouldThrow<IllegalArgumentException> {
            calcLineNumber(listOf("aaa", "bbb"), "zzz", 1, 0, true)
          }
        exception.message shouldContain "not found"
        exception.message shouldContain "zzz"
      }

      "calcLineNumber with insufficient occurrences" {
        val exception =
          shouldThrow<IllegalArgumentException> {
            calcLineNumber(listOf("aaa", "bbb"), "aaa", 2, 0, true)
          }
        exception.message shouldContain "not found"
        exception.message shouldContain "2"
      }

      "calcLineNumber with empty lines" {
        val exception =
          shouldThrow<IllegalArgumentException> {
            calcLineNumber(emptyList(), "aaa", 1, 0, true)
          }
        exception.message shouldContain "not found"
      }

      "calcLineNumber with negative offset produces line below 1" {
        // line 1 matched + offset -2 = line -1 + 1 = 0
        calcLineNumber(listOf("aaa", "bbb", "ccc"), "aaa", 1, -2, true) shouldBe -1
      }

      "calcLineNumber includes desc in not-found error" {
        val exception =
          shouldThrow<IllegalArgumentException> {
            calcLineNumber(listOf("aaa"), "zzz", 1, 0, true, "begin")
          }
        exception.message shouldContain "begin"
      }

      "calcLineNumber with single line file" {
        calcLineNumber(listOf("hello world"), "hello", 1, 0, true) shouldBe 1
      }

      "calcLineNumber with regex special chars" {
        val lines = listOf("foo()", "bar()", "baz()")
        calcLineNumber(lines, "foo\\(\\)", 1, 0, true) shouldBe 1
      }

      "calcLineNumber bottom-up with single match" {
        val lines = listOf("aaa", "bbb", "ccc")
        calcLineNumber(lines, "bbb", 1, 0, false) shouldBe 2
      }
    },
  )

