17→object Cache {
18→  internal suspend fun RoutingContext.displayCache() {
19→    call.respondHtmlTemplate(PageTemplate("srcref Content Cache")) {
20→      content {
21→        div("page-indent") {
22→          h2 { +"srcref Content Cache" }
23→          h3 { +"Cache Size: ${contentCache.size}" }
24→          if (contentCache.size > 0) {
25→            table {
26→              id = "cachetable"
27→              style = "width: 100%; border-collapse: collapse;"
28→              tr {
29→                th { +"Hits" }
30→                th { +"Last Access" }
31→                th { +"Age" }
32→                th { +"Size" }
33→                th { +"Lines" }
34→                th {
35→                  style = "padding-left: 5px; text-align: left;"
36→                  +"Url"
37→                }
38→                th {
39→                  style = "padding-left: 5px; text-align: left;"
40→                  +"ETag"
41→                }
42→              }
43→              contentCache.sortedByLastReferenced().forEach { (url, v) ->
44→                tr {
45→                  td {
46→                    style = "text-align: center;"
47→                    +v.hits.toString()
48→                  }
49→                  td {
50→                    style = "text-align: center;"
51→                    +v.lastReferenced.toString()
52→                  }
53→                  td {
54→                    style = "text-align: center;"
55→                    +v.age.toString()
56→                  }
57→                  td {
58→                    style = "text-align: center;"
59→                    +v.contentLength.toString()
60→                  }
61→                  td {
62→                    style = "text-align: center;"
63→                    +v.pageLines.size.toString()
64→                  }
65→                  td { +url.let { if (url.startsWith(RAW_PREFIX)) it.substring(RAW_PREFIX.length) else it } }
66→                  td { +formatEtag(v.etag) }
67→                }
68→              }
69→            }
70→          }
71→        }
72→      }
73→    }
74→  }
75→
76→  internal fun formatEtag(etag: String): String {
77→    if (etag.length <= 1) return etag
78→    val display = etag.substring(1, minOf(21, etag.length))
79→    return if (etag.length > 21) "$display..." else display
80→  }
81→}
