import com.pambrose.srcref.module
import io.kotest.core.spec.style.StringSpec
import io.kotest.matchers.shouldBe
import io.kotest.matchers.string.shouldContain
import io.kotest.matchers.string.shouldNotContain
import io.ktor.client.request.get
import io.ktor.client.statement.bodyAsText
import io.ktor.http.HttpStatusCode
import io.ktor.server.testing.testApplication

class RoutesTests :
  StringSpec(
    {
      // /ping

      "GET /ping returns pong" {
        testApplication {
          application { module() }
          client.get("/ping").apply {
            status shouldBe HttpStatusCode.OK
            bodyAsText() shouldBe "pong"
          }
        }
      }

      // /version

      "GET /version returns version page" {
        testApplication {
          application { module() }
          client.get("/version").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            body shouldContain "srcref Version"
            body shouldContain "Version:"
            body shouldContain "Release Date:"
          }
        }
      }

      // /what

      "GET /what returns explanation page" {
        testApplication {
          application { module() }
          client.get("/what").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            body shouldContain "What is srcref?"
            body shouldContain "line-specific"
            body shouldContain "regular expressions"
            body shouldContain "regex101.com"
            body shouldContain "/edit"
            body shouldContain "Back"
          }
        }
      }

      // /cache

      "GET /cache returns cache page" {
        testApplication {
          application { module() }
          client.get("/cache").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            body shouldContain "srcref Content Cache"
            body shouldContain "Cache Size:"
          }
        }
      }

      // /edit

      "GET /edit with no params shows empty form with Example Values button" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            body shouldContain "srcref - Dynamic Line-Specific GitHub Permalinks"
            body shouldContain "What is srcref?"
            body shouldContain "Username/Org Name:"
            body shouldContain "Repo Name:"
            body shouldContain "Branch Name:"
            body shouldContain "File Path:"
            body shouldContain "Begin Regex:"
            body shouldContain "Begin Occurrence:"
            body shouldContain "Begin Offset:"
            body shouldContain "Begin Search Direction:"
            body shouldContain "End Regex:"
            body shouldContain "End Occurrence:"
            body shouldContain "End Offset:"
            body shouldContain "End Search Direction:"
            body shouldContain "Generate URL"
            body shouldContain "Example Values"
            // No error section when no params
            body shouldNotContain "Exception:"
            body shouldNotContain "Reset Values"
          }
        }
      }

      "GET /edit with partial params shows form with error" {
        testApplication {
          application { module() }
          client.get("/edit?account=testuser").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            // Form still present
            body shouldContain "Username/Org Name:"
            body shouldContain "Generate URL"
            // Error section shown
            body shouldContain "Exception:"
            body shouldContain "Missing: repo value"
            body shouldContain "Reset Values"
            // No Example Values or Copy URL when params present
            body shouldNotContain "Example Values"
            body shouldNotContain "Copy URL"
          }
        }
      }

      "GET /edit form fields have correct input names" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            val body = bodyAsText()
            body shouldContain "name=\"account\""
            body shouldContain "name=\"repo\""
            body shouldContain "name=\"branch\""
            body shouldContain "name=\"path\""
            body shouldContain "name=\"bregex\""
            body shouldContain "name=\"boccur\""
            body shouldContain "name=\"boffset\""
            body shouldContain "name=\"btopd\""
            body shouldContain "name=\"eregex\""
            body shouldContain "name=\"eoccur\""
            body shouldContain "name=\"eoffset\""
            body shouldContain "name=\"etopd\""
          }
        }
      }

      "GET /edit form has radio buttons for search direction" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            val body = bodyAsText()
            body shouldContain "Top-down"
            body shouldContain "Bottom-up"
            body shouldContain "begin_topdown"
            body shouldContain "begin_bottomup"
            body shouldContain "end_topdown"
            body shouldContain "end_bottomup"
          }
        }
      }

      "GET /edit form has occurrence dropdowns with 10 options" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            val body = bodyAsText()
            body shouldContain "1st"
            body shouldContain "10th"
          }
        }
      }

      // /problem

      "GET /problem with msg shows error page" {
        testApplication {
          application { module() }
          client.get("/problem?msg=Test+Error+Message").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            body shouldContain "srcref Exception:"
            body shouldContain "Test Error Message"
            body shouldContain "Args:"
            body shouldContain "Edit Values"
          }
        }
      }

      "GET /problem without msg shows default message" {
        testApplication {
          application { module() }
          client.get("/problem").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            body shouldContain "srcref Exception:"
            body shouldContain "Missing message value"
          }
        }
      }

      "GET /problem Edit Values button links back to edit" {
        testApplication {
          application { module() }
          client.get("/problem?msg=err&account=user&repo=myrepo").apply {
            val body = bodyAsText()
            body shouldContain "/edit?"
            body shouldContain "account=user"
          }
        }
      }

      // /github

      "GET /github?edit shows edit page" {
        testApplication {
          application { module() }
          client.get("/github?edit").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            body shouldContain "srcref - Dynamic Line-Specific GitHub Permalinks"
            body shouldContain "Generate URL"
          }
        }
      }

      "GET /github with missing required param redirects to problem page" {
        testApplication {
          application { module() }
          // account present but repo missing — fails before any network call
          client.get("/github?account=user&bregex=test").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            body shouldContain "srcref Exception:"
            body shouldContain "Missing: repo value"
          }
        }
      }

      "GET /github?edit with params shows pre-filled form" {
        testApplication {
          application { module() }
          client.get("/github?edit&account=myuser&repo=myrepo").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            body shouldContain "myuser"
            body shouldContain "myrepo"
          }
        }
      }

      // /threaddump

      "GET /threaddump returns thread info" {
        testApplication {
          application { module() }
          client.get("/threaddump").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            (body.isNotEmpty()) shouldBe true
          }
        }
      }

      // /robots.txt

      "GET /robots.txt returns robots content" {
        testApplication {
          application { module() }
          client.get("/robots.txt").apply {
            status shouldBe HttpStatusCode.OK
            val body = bodyAsText()
            body shouldContain "User-agent: *"
            body shouldContain "Disallow: /error/"
            body shouldContain "Disallow: /error"
          }
        }
      }

      // / redirect

      "GET / redirects" {
        testApplication {
          application { module() }
          val noRedirectClient =
            createClient {
              followRedirects = false
            }
          noRedirectClient.get("/").apply {
            (status.value in 300..399) shouldBe true
          }
        }
      }

      // 404

      "GET nonexistent path returns 404" {
        testApplication {
          application { module() }
          client.get("/nonexistent").apply {
            status shouldBe HttpStatusCode.NotFound
            bodyAsText() shouldContain "Page not found"
            bodyAsText() shouldContain "/nonexistent"
          }
        }
      }

      // Static resources

      "GET /css/srcref.css serves stylesheet" {
        testApplication {
          application { module() }
          client.get("/css/srcref.css").apply {
            status shouldBe HttpStatusCode.OK
          }
        }
      }

      "GET /js/copyUrl.js serves JavaScript" {
        testApplication {
          application { module() }
          client.get("/js/copyUrl.js").apply {
            status shouldBe HttpStatusCode.OK
          }
        }
      }

      "GET /favicon.ico serves icon" {
        testApplication {
          application { module() }
          client.get("/favicon.ico").apply {
            status shouldBe HttpStatusCode.OK
          }
        }
      }

      // HTML template structure (PageTemplate)

      "HTML pages include meta charset utf-8" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            bodyAsText() shouldContain "charset=\"utf-8\""
          }
        }
      }

      "HTML pages include viewport meta tag" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            bodyAsText() shouldContain "viewport"
          }
        }
      }

      "HTML pages include CSS link" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            bodyAsText() shouldContain "css/srcref.css"
          }
        }
      }

      "HTML pages include GitHub icon" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            bodyAsText() shouldContain "github.com/pambrose/srcref"
          }
        }
      }

      "HTML pages include favicon links" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            val body = bodyAsText()
            body shouldContain "favicon.ico"
            body shouldContain "shortcut icon"
          }
        }
      }

      "Edit page has correct title" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            bodyAsText() shouldContain "<title>srcref</title>"
          }
        }
      }

      "Version page has correct title" {
        testApplication {
          application { module() }
          client.get("/version").apply {
            bodyAsText() shouldContain "<title>srcref Version</title>"
          }
        }
      }

      "What page has correct title" {
        testApplication {
          application { module() }
          client.get("/what").apply {
            bodyAsText() shouldContain "<title>What is srcref?</title>"
          }
        }
      }

      "Problem page has correct title" {
        testApplication {
          application { module() }
          client.get("/problem?msg=err").apply {
            bodyAsText() shouldContain "<title>srcref Exception</title>"
          }
        }
      }

      "Cache page has correct title" {
        testApplication {
          application { module() }
          client.get("/cache").apply {
            bodyAsText() shouldContain "<title>srcref Content Cache</title>"
          }
        }
      }

      // Edit page script include

      "Edit page includes copyUrl.js script" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            bodyAsText() shouldContain "js/copyUrl.js"
          }
        }
      }

      // Edit page tooltip content

      "Edit page has tooltip descriptions" {
        testApplication {
          application { module() }
          client.get("/edit").apply {
            val body = bodyAsText()
            body shouldContain "GitHub username or organization name"
            body shouldContain "GitHub repository name"
            body shouldContain "GitHub branch name"
            body shouldContain "File path in repository"
            body shouldContain "Regex used to determine the beginning match"
          }
        }
      }
    },
  )

