            body shouldContain "Username/Org Name:"
            body shouldContain "Generate URL"
            // Error section shown
            body shouldContain "Exception:"
            body shouldContain "Missing: repo value"
            body shouldContain "Reset Values"
            // No Example Values or Copy URL when params present
            body shouldNotContain "Example Values"
            body shouldNotContain "Copy URL"
          }
